{
  "filecontent": null,
  "partialurl": "mytickets",
  "feedbackpolicy": 756150000,
  "excludefromsearch": false,
  "hiddenfromsitemap": false,
  "enablerating": false,
  "isroot": false,
  "sharedpageconfiguration": true,
  "publishingstateid": "499c599d-1425-4031-96b2-d329588ae104",
  "pagetemplateid": "a0e5f938-a922-f111-8342-000d3ab2c460",
  "parentpageid": "8860f327-aa0e-4946-bcba-adc8936b0d63",
  "isofflinecached": false,
  "rootwebpageid": "4fff39b9-0923-f111-8341-000d3ab2bd64",
  "copy": "{% fetchxml tickets %}
<fetch>
  <entity name="it_request">
    <attribute name="it_requestid" />
    <attribute name="it_affecteddevice" />
    <attribute name="it_category" />
    <attribute name="it_categoryname" />
    <attribute name="it_priority" />
    <attribute name="it_priorityname" />
    <attribute name="it_requeststatus" />
    <attribute name="it_requeststatusname" />
    <attribute name="it_startdate" />
    <attribute name="it_newcolumn" />
    <attribute name="it_tickettitle" />
    <attribute name="it_ticketcreatedby" />
    <attribute name="createdby" />
    <filter type="and">
      <condition attribute="statecode" operator="eq" value="0" />
      <condition attribute="it_ticketcreatedby" operator="eq" value="{{user.id}}" />
    </filter>
  </entity>
</fetch>
{% endfetchxml %} {% fetchxml resolvedtickets %}
<fetch>
  <entity name="it_request">
    <attribute name="it_requestid" />
    <attribute name="it_affecteddevice" />
    <attribute name="it_category" />
    <attribute name="it_categoryname" />
    <attribute name="it_priority" />
    <attribute name="it_priorityname" />
    <attribute name="it_requeststatus" />
    <attribute name="it_requeststatusname" />
    <attribute name="it_startdate" />
    <attribute name="it_newcolumn" />
    <attribute name="it_tickettitle" />
    <attribute name="it_ticketcreatedby" />
    <filter type="and">
      <condition attribute="statecode" operator="eq" value="0" />
      <condition attribute="it_requeststatus" operator="eq" value="1" />
      <condition attribute="it_ticketcreatedby" operator="eq" value="{{user.id}}" />
    </filter>
  </entity>
</fetch>
{% endfetchxml %} {% fetchxml inprogresstickets %}
<fetch>
  <entity name="it_request">
    <attribute name="it_requestid" />
    <attribute name="it_affecteddevice" />
    <attribute name="it_category" />
    <attribute name="it_categoryname" />
    <attribute name="it_priority" />
    <attribute name="it_priorityname" />
    <attribute name="it_requeststatus" />
    <attribute name="it_requeststatusname" />
    <attribute name="it_startdate" />
    <attribute name="it_newcolumn" />
    <attribute name="it_tickettitle" />
    <attribute name="it_ticketcreatedby" />
    <filter type="and">
      <condition attribute="statecode" operator="eq" value="0" />
      <condition attribute="it_requeststatus" operator="eq" value="0" />
      <condition attribute="it_ticketcreatedby" operator="eq" value="{{user.id}}" />
    </filter>
  </entity>
</fetch>
{% endfetchxml %} {% fetchxml onholdtickets %}
<fetch>
  <entity name="it_request">
    <attribute name="it_requestid" />
    <attribute name="it_affecteddevice" />
    <attribute name="it_category" />
    <attribute name="it_categoryname" />
    <attribute name="it_priority" />
    <attribute name="it_priorityname" />
    <attribute name="it_requeststatus" />
    <attribute name="it_requeststatusname" />
    <attribute name="it_startdate" />
    <attribute name="it_newcolumn" />
    <attribute name="it_tickettitle" />
    <attribute name="it_ticketcreatedby" />
    <filter type="and">
      <condition attribute="statecode" operator="eq" value="0" />
      <condition attribute="it_requeststatus" operator="eq" value="3" />
      <condition attribute="it_ticketcreatedby" operator="eq" value="{{user.id}}" />
    </filter>
  </entity>
</fetch>
{% endfetchxml %}

<div class="hero hero--employee" style="padding:16px 16px 14px">
  <p class="hero-eyebrow hero-eyebrow--employee">My requests</p>
  <h1>My tickets</h1>
</div>

<div class="page-wrapper" id="pageWrapper">
  <main class="main">
    <div class="metric-grid">
      <div class="metric-card">
        <p class="metric-label">Total tickets</p>
        <p class="metric-value">{{ tickets.results.entities.size }}</p>
      </div>
      <div class="metric-card">
        <p class="metric-label">On Hold</p>
        <p class="metric-value metric-value--warn">{{ onholdtickets.results.entities.size }}</p>
      </div>
      <div class="metric-card">
        <p class="metric-label">In progress</p>
        <p class="metric-value metric-value--blue">{{ inprogresstickets.results.entities.size }}</p>
      </div>
      <div class="metric-card">
        <p class="metric-label">Resolved</p>
        <p class="metric-value metric-value--success">{{ resolvedtickets.results.entities.size }}</p>
      </div>
    </div>

    <div class="filter-bar">
      <input type="text" id="searchbox" placeholder="Search my tickets..." />
      <select>
        <option>All statuses</option>
        <option>New</option>
        <option>In progress</option>
        <option>On hold</option>
        <option>Resolved</option>
      </select>
      <select>
        <option>All categories</option>
        <option>Hardware</option>
        <option>Software</option>
        <option>Network</option>
        <option>Access</option>
      </select>
      <button class="btn-new">+ New ticket</button>
    </div>

    <div class="table-card">
      <div class="table-wrap">
        <table>
          <colgroup>
            <col style="width:80px" />
            <col style="width:200px" />
            <col style="width:75px" />
            <col style="width:70px" />
            <col style="width:85px" />
            <col style="width:100px" />
            <col style="width:55px" />
          </colgroup>
          <thead>
            <tr>
              <th>Ticket ID</th>
              <th>Title</th>
              <th>Category</th>
              <th>Priority</th>
              <th>Status</th>
              <th>Date</th>
              <th></th>
            </tr>
          </thead>
          <tbody id="ticketBody"></tbody>
        </table>
      </div>

      <!-- ── Pagination Footer ── -->
      <div class="table-footer">
        <span class="pagination-info" id="paginationInfo"></span>
        <nav class="pagination" id="pagination" aria-label="Ticket pages"></nav>
      </div>
    </div>
  </main>
</div>

<script src="https://code.jquery.com/jquery-3.6.0.min.js"></script>
<script>
  $(document).ready(function () {

    var tickets = [];
    var filteredTickets = [];

    {%if tickets.results.entities | size > 0 %}
    console.log('size: ', `{{ tickets.results.entities.size }}`)
    {% for ticket in tickets.results.entities %}

    tickets.push({
      "id": `{{ticket.it_newcolumn}}`,
      "title": `{{ticket.it_tickettitle}}`,
      "category": `{{ticket.it_category.label}}`,
      "priority": `{{ticket.it_priority.label}}`,
      "status": `{{ticket.it_requeststatus.label}}`,
      "effectivedate": `{{ticket.it_startdate | date: "%d/%M/%y" }}`,
      "reqguid": `{{ticket.it_requestid}}`
    })

    {% endfor %}
    {% endif %}
    console.log('tickets : ', tickets)

    var PER_PAGE = 3;   /* rows per page — adjust as needed */
    var cur = 1;
    var totalPg = Math.ceil(tickets.length / PER_PAGE);

    /* ── Sliding window: always exactly 3 page numbers ── */
    function getWindow() {
      var s = cur - 1;
      if (s < 1) s = 1;
      if (s + 2 > totalPg) s = Math.max(1, totalPg - 2);
      var win = [];
      for (var p = s; p <= s + 2 && p <= totalPg; p++) win.push(p);
      console.log('win', win)
      return win;
    }

    function renderTable(tickets) {
      var priorityLabel, statusLabel;
      var start = (cur - 1) * PER_PAGE;
      var rows = tickets.slice(start, start + PER_PAGE);
      var html = '';
      for (var i = 0; i < rows.length; i++) {
        var t = rows[i];
        if (t.priority == "Low") {
          priorityLabel = "low"
        }
        else if (t.priority == "Medium") {
          priorityLabel = "med"
        }
        else if (t.priority == "High") {
          priorityLabel = "high"
        }
        else if (t.priority == "Critical") {
          priorityLabel = "crit"
        };

        if (t.status == "Resolved") {
          statusLabel = "done"
        }
        else if (t.status == "In Progresss" || t.status == "New") {
          statusLabel = "prog"
        }

        html += '<tr>' +
          '<td>' + t.id + '</td>' +
          '<td>' + t.title + '</td>' +
          '<td>' + t.category + '</td>' +
          '<td><span class="badge badge--' + priorityLabel + '">' + t.priority + '</span></td>' +
          '<td><span class="badge badge--' + statusLabel + '">' + t.status + '</span></td>' +
          '<td>' + t.effectivedate + '</td>' +
          '<td><a href="/ticketdetail/?id='+ t.reqguid +'" class="tbl-btn tbl-btn--view">View \u2192</a></td>' +
          '</tr>';
      }
      document.getElementById('ticketBody').innerHTML = html;
      var end = Math.min(start + PER_PAGE, tickets.length);
      document.getElementById('paginationInfo').textContent =
        'Showing ' + (start + 1) + '\u2013' + end + ' of ' + tickets.length + ' tickets';
    }

    function renderPagination() {
      var win = getWindow();
      var html = '';

      /* Prev button */
      html += '<button id="prevBtn" class="page-btn page-btn--nav"' +
        (cur === 1 ? ' disabled' : '') + ' aria-label="Previous page">' +
        '<svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="1.8"' +
        ' stroke-linecap="round" stroke-linejoin="round"><polyline points="10,3 6,8 10,13"/></svg>' +
        '</button>';

      /* 3 page number buttons */
      for (var i = 0; i < win.length; i++) {
        var p = win[i];
        html += `<button id="pageBtn_${i + 1}" class="page-btn${p === cur ? ' active' : ''}"${p === cur ? ' aria-current="page"' : ''}>${p}</button>`;
      }

      /* Next button */
      html += '<button id="nextBtn" class="page-btn page-btn--nav"' +
        (cur === totalPg ? ' disabled' : '') + ' aria-label="Next page">' +
        '<svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="1.8"' +
        ' stroke-linecap="round" stroke-linejoin="round"><polyline points="6,3 10,8 6,13"/></svg>' +
        '</button>';

      document.getElementById('pagination').innerHTML = html;
    }

    function go(p) {
      if (p < 1 || p > totalPg) return;
      cur = p;

      const value = document.getElementById("searchbox").value.trim().toLowerCase();
      if (value === "") {
        renderTable(tickets);
      }
      else {
        renderTable(filteredTickets);
      }

      renderPagination();
    }

    /* ── Init ── */
    renderTable(tickets);
    renderPagination();


    document.getElementById("pagination").addEventListener("click", function (e) {

      const btn = e.target.closest("button");
      if (!btn) return;

      if (btn.id === "prevBtn" && cur > 1) {
        go(cur - 1);
      }

      else if (btn.id === "nextBtn" && cur < totalPg) {
        go(cur + 1);
      }

      else if (btn.id.startsWith("pageBtn_")) {
        const page = parseInt(btn.id.split("_")[1]);
        console.log('page:', page)
        go(page);
      }

    });

    document.getElementById("searchbox").addEventListener("change", function () {
      const value = this.value.trim().toLowerCase();

      if (value === "") {
        filteredTickets = tickets; // reset
      } else {
        filteredTickets = tickets.filter(t =>
          (t.title || "").toLowerCase().includes(value) ||
          (t.category || "").toLowerCase().includes(value) ||
          (t.priority || "").toLowerCase().includes(value) ||
          (t.status || "").toLowerCase().includes(value) ||
          (t.id || "").toLowerCase().includes(value)
        );
      }

      cur = 1;
      totalPg = Math.ceil(filteredTickets.length / PER_PAGE);
      console.log('filtered', filteredTickets)

      renderTable(filteredTickets);
      renderPagination();
    });

  })
</script>
<div class="row sectionBlockLayout text-start" style="display: flex; flex-wrap: wrap; margin: 0px; min-height: auto; padding: 8px;">
  <div class="container" style="padding: 0px; display: flex; flex-wrap: wrap;"><div class="col-lg-12 columnBlockLayout" style="flex-grow: 1; display: flex; flex-direction: column; min-width: 250px;"></div></div>
</div>
<div class="row sectionBlockLayout text-start" style="display: flex; flex-wrap: wrap; margin: 0px; min-height: auto; padding: 8px;">
  <div class="container" style="padding: 0px; display: flex; flex-wrap: wrap;"><div class="col-lg-12 columnBlockLayout" style="flex-grow: 1; display: flex; flex-direction: column; min-width: 250px;"></div></div>
</div>"
}

